/**
 * Composant PlanCard : affiche un forfait mobile
 * - plan["Opérateur 2"]      : nom de l'opérateur
 * - plan.Offre                : nom de l'offre
 * - plan["Données mobiles"]   : volume de data (ex. "200 Go")
 * - plan.Couverture           : type de couverture (ex. "5G")
 * - plan.Engagement           : ex. "Sans engagement"
 * - plan["Tarif qui augmente"]: ex. "Sans tarif qui augmente"
 * - plan.Prix                 : ex. "12€"
 * - plan.Économies            : nombre (ex. 130)
 * - plan.prix                 : "yes" ou "" (filtre « Le moins cher »)
 * - plan.qualité              : "yes" ou "" (filtre « Le plus d'options »)
 * - plan.sav                  : "yes" ou "" (filtre « Sans engagement »)
 * - plan["Lien d affiliation"]: URL d'affiliation
 *
 * Props :
 * - onViewClick : fonction à appeler quand on clique sur "Voir"
 */
function PlanCard({
  plan,
