  .plan-card {
    grid-template-columns: var(--plan-card-col1-width) var(--plan-card-col2-width); /* 2 colonnes */
    /* grid-template-rows: auto auto;  Optionnel, auto est par défaut */
  }
  .operator-info {
    /* S'étend sur les 2 colonnes si besoin, ou reste dans la 1ère */
