  }
  .center-zones {
     /* S'étend sur les 2 colonnes si besoin, ou reste dans la 2ème */
  }
  .cta-button {
    grid-column: 1 / -1; /* Le bouton prend toute la largeur de la grille (sur sa propre "ligne") */
    justify-self: center; /* Centre le bouton lui-même */
    margin-top: 20px; /* Ajoute un espace au-dessus */
    max-width: 300px;
  }

  .operator-info {
    /* min-width: 250px; -- Déjà géré par la grille */
  }
}

/* Pour téléphones mobiles (tout en une colonne) */
@media (max-width: 767.98px) {
  .plan-card {
    grid-template-columns: 1fr; /* Toutes les sections en une seule colonne */
    justify-items: center; /* Centre les enfants de la grille (operator-info, center-zones, cta-button) */
    gap: 20px;
