/**
 * Composant PlanCard : affiche un forfait mobile
 * - plan["Opérateur 2"]      : nom de l'opérateur
 * - plan.Offre                : nom de l'offre
 * - plan["Données mobiles"]   : volume de data (ex. "200 Go")
 * - plan.Couverture           : type de couverture (ex. "5G")
 * - plan.Engagement           : ex. "Sans engagement"
 * - plan["Tarif qui augmente"]: ex. "Sans tarif qui augmente"
 * - plan.Prix                 : ex. "12€"
 * - plan.Économies            : nombre (ex. 130)
 * - plan.prix                 : "yes" ou "" (filtre « Le moins cher »)
 * - plan.qualité              : "yes" ou "" (filtre « Le plus d'options »)
 * - plan.sav                  : "yes" ou "" (filtre « Sans engagement »)
 * - plan["Lien d affiliation"]: URL d'affiliation
 *
 * Props :
 * - onViewClick : fonction à appeler quand on clique sur "Voir"
 */
function PlanCard({ plan, onViewClick }) {
  return (
    <div className="plan-card">
      {/* ===== Zone 1 : Logo + nom opérateur + nom offre ===== */}
      <div className="operator-info">
        <img
          src={plan.logo}
          className="operator-logo"
        />
        <div className="operator-texts">
          <div className="operator-name">{plan["Opérateur 2"]}</div>
          <div className="offer-name">{plan.Offre}</div>
        </div>
      </div>

      {/* ===== Centre : trois colonnes : Data / Engagement / Prix ===== */}
      <div className="center-zones">
        {/* ---- Colonne A : Données mobiles & 5G ---- */}
        <div className="column-data">
          <div className="data-amount">
            {plan["Données mobiles"]}
          </div>
          <div className="data-network">
            {plan.Couverture}
          </div>
        </div>

        {/* ---- Colonne B : Engagement & Tarif qui augmente ---- */}
        <div className="column-engagement">
          <div className="engagement-status">
            {plan.Engagement}
          </div>
          <div className="rate-nowrap">
            {plan["Tarif qui augmente"]}
          </div>
        </div>

        {/* ---- Colonne C : Prix & Économies ---- */}
        <div className="column-price">
          {/* ===== Prix avec "/mois" sur la même ligne ===== */}
          <div className="offer-price">
            <b>{plan.Prix}</b><span>/mois</span>
          </div>
          <div className="offer-savings" style={{color: plan.savingsTextColor }}>
            <b>{plan.savings}€</b><span>{plan.savingsUnit}</span>
          </div>
        </div>
      </div>

      {/* ===== Zone 4 : Bouton "Voir" ===== */}
      {/* Lorsque l'on clique, on appelle onViewClick(plan) */}
      <button
        className="cta-button"
        onClick={() => onViewClick(plan)}
      >
        Voir
      </button>
    </div>
  );
}

/**
 * Composant Filters : les trois boutons-filtre
 * - activeFilter : chaîne "prix" | "qualité" | "sav" | null
 * - onChange     : fonction pour signifier qu'on a changé de filtre
 */
function Filters({ activeFilter, onChange }) {
  return (
    <div className="header">
      <div
        id="btn-prix"
        className={"feature-card " + (activeFilter === "prix" ? " active" : "")}
        onClick={() => onChange(activeFilter === 'prix' ? null : 'prix')}
      >
        <div className="icon">$</div>
        <div className="text">Le moins cher</div>
      </div>
      <div
        id="btn-qualité"
				className={"feature-card " + (activeFilter === "qualité" ? " active" : "")}
        onClick={() => onChange(activeFilter === 'qualité' ? null : 'qualité')}
      >
        <div className="icon">👑</div>
        <div className="text">Le plus d'options</div>
      </div>
      <div
        id="btn-sav"
				className={"feature-card " + (activeFilter === "sav" ? " active" : "")}
        onClick={() => onChange(activeFilter === 'sav' ? null : 'sav')}
      >
        <div className="icon">✓</div>
        <div className="text">Sans engagement</div>
      </div>
    </div>
  );
}

/**
 * Composant MobilePlans :
 * - Récupère les données depuis appsmith.model.plan (Default Model)
 * - Gère l'affichage pendant le chargement des données.
 * - Filtre sur { plan[activeFilter] === "yes" } si activeFilter n'est pas null
 * - Affiche jusqu'aux 24 premiers plans
 * - Utilise TransitionGroup + CSSTransition pour animer fade+slide
 * - Reçoit onViewClick pour ouvrir la modal
 */
function MobilePlans({ activeFilter, onViewClick }) {
  const isLoading = appsmith.model.loading;
  const [dotCount, setDotCount] = useState(1);

  React.useEffect(() => {
    let intervalId;

    if (isLoading) {
      intervalId = setInterval(() => {
        setDotCount(prevCount => (prevCount % 3) + 1);
      }, 400);
    }

    return () => clearInterval(intervalId);
  }, [isLoading]);

  if (isLoading) {
    return (
      <p style={{ textAlign: 'center', color: '#596D7B', marginTop: '40px', fontSize: '18px' }}>
        Chargement{'.'.repeat(dotCount)}
      </p>
    );
  }

  const dataFromModel = appsmith.model.plan || [];
  const allPlans = Array.isArray(dataFromModel)
    ? dataFromModel
    : Object.values(dataFromModel);

  const firstTwentyFour = allPlans.slice(0, 24);

  const plansFiltres = activeFilter
    ? firstTwentyFour.filter(plan => plan[activeFilter] === 'yes')
    : firstTwentyFour;

  return (
    <div id="plans-container">
      <TransitionGroup>
        {plansFiltres.map((plan, idx) => {
          const keyId = plan.Position != null ? plan.Position : idx;
          return (
            <CSSTransition
              key={keyId}
              timeout={300}
              classNames="plan"
            >
              <PlanCard plan={plan} onViewClick={onViewClick} />
            </CSSTransition>
          );
        })}
      </TransitionGroup>

      {/* Afficher ce message uniquement si la recherche est terminée et qu'il n'y a aucun résultat */}
      {!isLoading && (
        <p style={{ textAlign: 'center', color: '#596D7B', marginTop: '40px' }}>
          Aucune offre ne correspond à ce filtre.
        </p>
      )}
    </div>
  );
}


/**
 * Composant principal App :
 * - Gère l'état `activeFilter`
 * - Gère l'état `selectedPlan` pour la pop‐up
 * - Affiche <Filters />, <MobilePlans />, puis <Modal />
 */
function App() {
  // "prix" | "qualité" | "sav" | null
  const [activeFilter, setActiveFilter] = useState(null);

  // Quand on veut ouvrir la modal, on passe l'objet plan
  const openModal = (plan) => {
    appsmith.triggerEvent("openModal", {"plan": plan});
  };

  return (
    <div>
      <Filters activeFilter={activeFilter} onChange={setActiveFilter} />
      <MobilePlans activeFilter={activeFilter} onViewClick={openModal} />
    </div>
  );
}

// On monte notre App dans <div id="root">
appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById('root'));
});

appsmith.onModelChange((new_model) => {
	appsmith.model = new_model;
	ReactDOM.render(<App />, document.getElementById('root'));
});
